SELECT COUNT(DISTINCT S.PK_SIAPE) FROM SERVIDOR S JOIN CARGO C ON C.FK_SIAPE = S.PK_SIAPE WHERE LOWER(COALESCE(S.CONTRATO,'')) = 'efetivos' AND (LOWER(COALESCE(S.AREA_INGRESSO,'')) LIKE '%ciencia da computacao%' OR LOWER(COALESCE(S.AREA_INGRESSO,'')) LIKE '%ciencia da computacao%' OR LOWER(COALESCE(S.AREA_INGRESSO_OG,'')) LIKE '%ciencia da computacao%' OR LOWER(COALESCE(S.AREA_INGRESSO_OG,'')) LIKE '%ciencia da computacao%') AND (LOWER(COALESCE(C.SIGLA_CAMPUS,'')) = 'apa' OR LOWER(COALESCE(S.SIGLA_CAMPUS,'')) = 'apa') AND C.DATA_ENTRADA <= '2022-12-31' AND (C.DATA_SAIDA IS NULL OR C.DATA_SAIDA >= '2022-01-01')